import { HttpErrorResponse } from "@angular/common/http";
import { Component, OnInit, ViewChild } from "@angular/core";
import { SegmentCustomEvent } from "@ionic/angular";
import { AlertService } from "src/app/core/services/alert.service";
import { MohassilAuthService } from "src/app/core/services/AuthenticationServices/mohassil-auth.service";
import { LoanApplicationsService } from "src/app/core/services/loan-applications.service";
import { LoansService } from "src/app/core/services/loans.service";
import { CosignersComponent } from "src/app/views/components/cosigners/cosigners.component";
import {
  ClientInfo,
  CosignersInfo,
} from "src/app/views/Models/Client/ClientInfo";
import { updateLoanApplicationCosigners } from "src/app/views/Models/LoanApplication/UpdateLoanApplicationCosigners";
import { SearchResult } from "src/app/views/Models/References/SearchResult";

interface SegmentInterface {
  visible: boolean;
  segmentsData: {
    name: string;
    windowCode: string;
    pageAction: number;
    disable: boolean;
    isSegmentSelected: boolean;
  }[];
}
interface ClientSearchInterface {
  visible: boolean;
  searchResult: SearchResult;
}
@Component({
  selector: "app-change-cosigners",
  templateUrl: "./change-cosigners.page.html",
  styleUrls: ["./change-cosigners.page.scss"],
})
export class ChangeCosignersPage implements OnInit {
  @ViewChild(CosignersComponent) cosignersComponent!: CosignersComponent;
  showLoader: boolean = false;
  segmentInterface: SegmentInterface;
  clientSearchInterface: ClientSearchInterface;
  loanInformation: {
    orgCode: string;
    clientName: string;
    clientCode: string;
    clientNationId: string;
    applicationKey: string;
    loanKey: string;
    loanAmount: number;
    loanDate: string;
  } = null;
  cosignerParameterForClientInfo: ClientInfo = null;
  selectedCosigners: CosignersInfo[];

  constructor(
    private authServices: MohassilAuthService,
    private alertService: AlertService,
    private loanService: LoansService,
    private loanApplicationService: LoanApplicationsService
  ) {}

  async ngOnInit() {
    this.initState();
    await this.setPagesPermission();
  }
  initState() {
    this.segmentInterface = {
      visible: true,
      segmentsData: [
        {
          name: "قروض غير المصدرة",
          windowCode: "5671",
          disable: false,
          isSegmentSelected: false,
          pageAction: 0,
        },
        {
          name: "قروض المصدرة",
          windowCode: "5672",
          disable: false,
          isSegmentSelected: false,
          pageAction: 1,
        },
      ],
    };
    this.clientSearchInterface = {
      visible: true,
      searchResult: null,
    };
  }
  async setPagesPermission() {
    const accessRight = (await this.authServices.getAccessRights()).map(
      (pages) => pages.window_code
    );
    this.segmentInterface.segmentsData.forEach((segment) => {
      segment.disable = !accessRight.includes(segment.windowCode);
    });
  }
  get selectedSegment() {
    // Find the first segment that is selected
    const selected = this.segmentInterface.segmentsData.find(
      (segment) => segment.isSegmentSelected
    );

    // If no selected segment, find the first segment that is not disabled (having permission on it)
    return (
      selected ||
      this.segmentInterface.segmentsData.find((segment) => !segment.disable)
    );
  }
  onSegmentChange(event: any) {
    const segmentEvent = event as SegmentCustomEvent;
    const selectedWindowCode = segmentEvent.detail.value;
    this.segmentInterface.segmentsData.forEach(
      (segment) =>
        (segment.isSegmentSelected = segment.windowCode === selectedWindowCode)
    );
    this.resetClientSearchComponent();
  }
  private handleError(error: unknown) {
    let errorMessage: string;

    if (error instanceof HttpErrorResponse) {
      errorMessage = JSON.stringify(error.error);
    } else if (error instanceof Error) {
      errorMessage = error.message;
    } else {
      errorMessage = String(error);
    }

    this.alertService.showAlertError(errorMessage, false);
    console.error("Error:", error);
  }
  resetClientSearchComponent() {
    this.clientSearchInterface.visible = false;
    setTimeout(() => (this.clientSearchInterface.visible = true), 0);
  }
  async searchResult(searchResult: SearchResult) {
    try {
      this.showLoader = true;
      console.log(searchResult);
      this.clientSearchInterface.searchResult = searchResult;
      await this.patchingFormGroup();
      this.clientSearchInterface.visible = false;
    } catch (error) {
      this.handleError(error);
    } finally {
      this.showLoader = false;
    }
  }
  backButton() {
    this.clientSearchInterface.visible = true;
  }
  async patchingFormGroup() {
    const [loan, cosigners] = await Promise.all([
      this.loanService
        .getLoanInformationByLoanKey(
          Number(this.clientSearchInterface.searchResult.loan_key)
        )
        .toPromise(),
      await this.loanApplicationService.getLoanApplicationCosigners(
        this.clientSearchInterface.searchResult.application_key.toString()
      ),
    ]);
    this.loanInformation = {
      clientName: this.clientSearchInterface.searchResult.client_name,
      loanAmount: loan.loanAmount,
      loanDate: loan.loanDate,
      loanKey: loan.loanKey.toString(),
      clientCode:
        this.clientSearchInterface.searchResult.client_code.toString(),
      clientNationId: this.clientSearchInterface.searchResult.nation_id,
      orgCode: loan.orgCode.toString(),
      applicationKey:
        this.clientSearchInterface.searchResult.application_key.toString(),
    };
    this.cosignerParameterForClientInfo = {
      org_code: loan.orgCode.toString(),
      client_code:
        this.clientSearchInterface.searchResult.client_code.toString(),
      nation_id: this.clientSearchInterface.searchResult.nation_id,
    };

    this.selectedCosigners = cosigners.map((cosigner) => ({
      ...cosigner,
    }));
  }
  extractCosignersFromComponent() {
    return this.cosignersComponent.getSelectedCosigners();
  }
  async saveButton() {
    try {
      this.showLoader = true;
      if (!(await this.alertService.SaveAlert())) return;

      const cosigners = this.extractCosignersFromComponent();
      const cosignerBody = cosigners.map((cosigner, index) => ({
        row_no: index + 1,
        client_key: Number(cosigner.coClientKey),
      }));

      await this.loanApplicationService.updateLoanApplicationCosigners({
        application_key: Number(this.loanInformation.applicationKey),
        cosigners: cosignerBody,
      });
      await this.alertService.showAlertConfirm("لقد تم التعديل بنجاح", true);
    } catch (error) {
      this.handleError(error);
    } finally {
      this.showLoader = false;
    }
  }
}
